     1|/**
     2| * Passwordless owner sign-in.
     3| *
     4| * POST /api/ivx/owner-passwordless-login
     5| *   body: { email }
     6| *
     7| * The owner types ONLY their email. The backend:
     8| *   1. Validates the email is in the owner allowlist
     9| *      (IVX_OWNER_REGISTRATION_EMAILS / IVX_BASELINE_OWNER_EMAILS).
    10| *   2. Uses the Supabase admin (service-role) client to find the owner auth user
    11| *      (creating + confirming them if they do not exist yet).
    12| *   3. Self-heals: sets the user's password to the configured
    13| *      IVX_OWNER_PASSWORD so the password grant always succeeds, even if the
    14| *      password drifted in Supabase. This is the fix for the recurring
    15| *      "invalid_credentials" block the owner hit.
    16| *   4. Performs a server-side password grant against Supabase Auth and returns
    17| *      the resulting session tokens (access_token, refresh_token, expires_at).
    18| *
    19| * The password is NEVER sent back to the client. The client installs the
    20| * returned session via supabase.auth.setSession(), which produces a real
    21| * Supabase session — so owner-AI chat approval (allowlist + bearer check)
    22| * works automatically.
    23| */
    24|import { createClient, type SupabaseClient } from '@supabase/supabase-js';
    25|import { ownerOnlyJson, ownerOnlyOptions } from './owner-only';
    26|import { getIVXOwnerEmailAllowlist } from '../../expo/shared/ivx/access-control';
    27|
    28|const DEPLOYMENT_MARKER = 'ivx-owner-passwordless-login-2026-07-06t0000z';
    29|
    30|const PASSWORDLESS_HEADERS = {
    31|  'Content-Type': 'application/json',
    32|  'Cache-Control': 'no-store',
    33|  'Access-Control-Allow-Origin': '*',
    34|  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    35|  'Access-Control-Allow-Methods': 'POST, OPTIONS',
    36|} as const;
    37|
    38|function readTrimmed(value: unknown): string {
    39|  return typeof value === 'string' ? value.trim() : '';
    40|}
    41|
    42|function sanitizeEmail(value: unknown): string {
    43|  return readTrimmed(value).toLowerCase();
    44|}
    45|
    46|function isValidEmail(email: string): boolean {
    47|  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
    48|}
    49|
    50|function nowIso(): string {
    51|  return new Date().toISOString();
    52|}
    53|
    54|function json(payload: Record<string, unknown>, status: number = 200): Response {
    55|  return new Response(JSON.stringify(payload), { status, headers: PASSWORDLESS_HEADERS });
    56|}
    57|
    58|function readEnv(name: string): string {
    59|  return (process.env[name] ?? '').trim();
    60|}
    61|
    62|function resolveSupabaseUrl(): string {
    63|  return readEnv('EXPO_PUBLIC_SUPABASE_URL') || readEnv('SUPABASE_URL');
    64|}
    65|
    66|function resolveServiceRoleKey(): string {
    67|  return readEnv('SUPABASE_SERVICE_ROLE_KEY') || readEnv('SUPABASE_SERVICE_KEY');
    68|}
    69|
    70|function resolveAnonKey(): string {
    71|  return readEnv('EXPO_PUBLIC_SUPABASE_ANON_KEY');
    72|}
    73|
    74|function createAdminClient() {
    75|  const supabaseUrl = resolveSupabaseUrl();
    76|  const serviceRoleKey = resolveServiceRoleKey();
    77|  if (!supabaseUrl) {
    78|    throw new Error('Supabase URL is not configured on the backend (EXPO_PUBLIC_SUPABASE_URL).');
    79|  }
    80|  if (!serviceRoleKey) {
    81|    throw new Error('Supabase service role key is not configured on the backend (SUPABASE_SERVICE_ROLE_KEY).');
    82|  }
    83|  return createClient(supabaseUrl, serviceRoleKey, {
    84|    auth: { autoRefreshToken: false, persistSession: false },
    85|  });
    86|}
    87|
    88|type OwnerSessionResponse = {
    89|  success: true;
    90|  accessToken: string;
    91|  refreshToken: string;
    92|  expiresAt: number;
    93|  expiresAtIso: string;
    94|  userId: string;
    95|  email: string;
    96|  passwordSelfHealed: boolean;
    97|  authUserCreated: boolean;
    98|  deploymentMarker: string;
    99|  timestamp: string;
   100|};
   101|
   102|type OwnerSessionFailure = {
   103|  success: false;
   104|  message: string;
   105|  rootCause: string;
   106|  deploymentMarker: string;
   107|  timestamp: string;
   108|};
   109|
   110|/** Server-side password grant against the Supabase Auth token endpoint. */
   111|async function passwordGrant(supabaseUrl: string, email: string, password: string): Promise<{
   112|  ok: boolean;
   113|  accessToken?: string;
   114|  refreshToken?: string;
   115|  expiresAt?: number;
   116|  errorMessage?: string;
   117|  errorStatus?: number;
   118|}> {
   119|  const endpoint = `${supabaseUrl.replace(/\/+$/, '')}/auth/v1/token?grant_type=password`;
   120|  const anonKey = resolveAnonKey();
   121|  if (!anonKey) {
   122|    return { ok: false, errorMessage: 'Supabase anon key is not configured on the backend.' };
   123|  }
   124|  const controller = new AbortController();
   125|  const timer = setTimeout(() => controller.abort(), 20_000);
   126|  try {
   127|    const response = await fetch(endpoint, {
   128|      method: 'POST',
   129|      headers: {
   130|        'Content-Type': 'application/json',
   131|        apikey: anonKey,
   132|        Authorization: `Bearer ${anonKey}`,
   133|      },
   134|      body: JSON.stringify({ email, password }),
   135|      signal: controller.signal,
   136|    });
   137|    const text = await response.text();
   138|    let parsed: Record<string, unknown> = {};
   139|    try {
   140|      parsed = text ? (JSON.parse(text) as Record<string, unknown>) : {};
   141|    } catch {
   142|      return { ok: false, errorMessage: `Supabase returned non-JSON auth response (HTTP ${response.status}).` };
   143|    }
   144|    if (!response.ok) {
   145|      const message = typeof parsed.error_description === 'string'
   146|        ? parsed.error_description
   147|        : typeof parsed.msg === 'string'
   148|          ? parsed.msg
   149|          : typeof parsed.error === 'string'
   150|            ? parsed.error
   151|            : `Supabase rejected the password grant (HTTP ${response.status}).`;
   152|      return { ok: false, errorMessage: message, errorStatus: response.status };
   153|    }
   154|    const accessToken = typeof parsed.access_token === 'string' ? parsed.access_token : '';
   155|    const refreshToken = typeof parsed.refresh_token === 'string' ? parsed.refresh_token : '';
   156|    const expiresAt = typeof parsed.expires_at === 'number' ? parsed.expires_at : 0;
   157|    if (!accessToken || !refreshToken) {
   158|      return { ok: false, errorMessage: 'Supabase did not return access_token/refresh_token.' };
   159|    }
   160|    return { ok: true, accessToken, refreshToken, expiresAt };
   161|  } catch (error) {
   162|    return { ok: false, errorMessage: error instanceof Error ? error.message : 'Network failure during password grant.' };
   163|  } finally {
   164|    clearTimeout(timer);
   165|  }
   166|}
   167|
   168|export function ivxOwnerPasswordlessLoginOptions(): Response {
   169|  return ownerOnlyOptions();
   170|}
   171|
   172|export async function handleIVXOwnerPasswordlessLogin(request: Request): Promise<Response> {
   173|  if (request.method !== 'POST') {
   174|    return ownerOnlyJson({ success: false, message: 'Method not allowed.', deploymentMarker: DEPLOYMENT_MARKER }, 405);
   175|  }
   176|
   177|  let body: Record<string, unknown> = {};
   178|  try {
   179|    body = (await request.json().catch(() => ({}))) as Record<string, unknown>;
   180|  } catch {
   181|    body = {};
   182|  }
   183|  const email = sanitizeEmail(body.email);
   184|
   185|  if (!isValidEmail(email)) {
   186|    const failure: OwnerSessionFailure = {
   187|      success: false,
   188|      message: 'A valid owner email is required.',
   189|      rootCause: 'missing_or_invalid_email',
   190|      deploymentMarker: DEPLOYMENT_MARKER,
   191|      timestamp: nowIso(),
   192|    };
   193|    return ownerOnlyJson(failure, 400);
   194|  }
   195|
   196|  const allowlist = getIVXOwnerEmailAllowlist();
   197|  if (!allowlist.includes(email)) {
   198|    const failure: OwnerSessionFailure = {
   199|      success: false,
   200|      message: 'This email is not on the owner allowlist. Owner login is restricted to the configured owner.',
   201|      rootCause: 'email_not_allowlisted',
   202|      deploymentMarker: DEPLOYMENT_MARKER,
   203|      timestamp: nowIso(),
   204|    };
   205|    return ownerOnlyJson(failure, 403);
   206|  }
   207|
   208|  const ownerPassword = readEnv('IVX_OWNER_PASSWORD');
   209|  if (!ownerPassword) {
   210|    const failure: OwnerSessionFailure = {
   211|      success: false,
   212|      message: 'IVX_OWNER_PASSWORD is not configured on the backend. Set it in the Render environment to enable passwordless owner login.',
   213|      rootCause: 'owner_password_not_configured',
   214|      deploymentMarker: DEPLOYMENT_MARKER,
   215|      timestamp: nowIso(),
   216|    };
   217|    return ownerOnlyJson(failure, 500);
   218|  }
   219|
   220|  const supabaseUrl = resolveSupabaseUrl();
   221|  if (!supabaseUrl) {
   222|    const failure: OwnerSessionFailure = {
   223|      success: false,
   224|      message: 'Supabase URL is not configured on the backend.',
   225|      rootCause: 'supabase_url_not_configured',
   226|      deploymentMarker: DEPLOYMENT_MARKER,
   227|      timestamp: nowIso(),
   228|    };
   229|    return ownerOnlyJson(failure, 500);
   230|  }
   231|
   232|  let adminClient: SupabaseClient;
   233|  try {
   234|    adminClient = createAdminClient();
   235|  } catch (error) {
   236|    const failure: OwnerSessionFailure = {
   237|      success: false,
   238|      message: error instanceof Error ? error.message : 'Failed to initialize Supabase admin client.',
   239|      rootCause: 'admin_client_init_failed',
   240|      deploymentMarker: DEPLOYMENT_MARKER,
   241|      timestamp: nowIso(),
   242|    };
   243|    return ownerOnlyJson(failure, 500);
   244|  }
   245|
   246|  // Locate the owner auth user (list + match by email).
   247|  let authUserId: string | null = null;
   248|  let authUserCreated = false;
   249|  try {
   250|    const { data: listData, error: listError } = await adminClient.auth.admin.listUsers({ page: 1, perPage: 1000 });
   251|    if (listError) {
   252|      const failure: OwnerSessionFailure = {
   253|        success: false,
   254|        message: `Supabase admin listUsers failed: ${listError.message}`,
   255|        rootCause: 'admin_list_users_failed',
   256|        deploymentMarker: DEPLOYMENT_MARKER,
   257|        timestamp: nowIso(),
   258|      };
   259|      return ownerOnlyJson(failure, 502);
   260|    }
   261|    const users = Array.isArray(listData?.users) ? listData.users : [];
   262|    const match = users.find((u) => sanitizeEmail(u.email) === email);
   263|    authUserId = match?.id ?? null;
   264|  } catch (error) {
   265|    const failure: OwnerSessionFailure = {
   266|      success: false,
   267|      message: error instanceof Error ? error.message : 'Failed to list Supabase auth users.',
   268|      rootCause: 'admin_list_users_threw',
   269|      deploymentMarker: DEPLOYMENT_MARKER,
   270|      timestamp: nowIso(),
   271|    };
   272|    return ownerOnlyJson(failure, 502);
   273|  }
   274|
   275|  let passwordSelfHealed = false;
   276|
   277|  if (!authUserId) {
   278|    // Create the owner auth user with the configured password + confirmed email.
   279|    try {
   280|      const { data, error } = await adminClient.auth.admin.createUser({
   281|        email,
   282|        password: ownerPassword,
   283|        email_confirm: true,
   284|        user_metadata: {
